UPDATE ai_analysis_reports
SET
    status = 'PENDING',
    retry_count = retry_count + 1,
    analysis_error_code = NULL,
    updated_at = CURRENT_TIMESTAMP
WHERE report_id = #{reportId}
  AND user_id = #{userId}
  AND status = 'FAILED'
  AND retry_count = #{retryCount}
